import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const b=JSON.parse('{"title":"18、月【XVIII】","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/4.综合类/替身/阿尔卡纳/18、月【XVIII】.md","filePath":"4.资源分区/2.改造与功法/改造/4.综合类/替身/阿尔卡纳/18、月【XVIII】.md"}'),d={name:"4.资源分区/2.改造与功法/改造/4.综合类/替身/阿尔卡纳/18、月【XVIII】.md"};function i(_,a,p,l,I,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"_18、月【xviii】",tabindex:"-1"},[s("18、月【XVIII】 "),e("a",{class:"header-anchor",href:"#_18、月【xviii】","aria-label":'Permalink to "18、月【XVIII】"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调011")])])],-1),o('<h1 id="月亮" tabindex="-1">月亮 <a class="header-anchor" href="#月亮" aria-label="Permalink to &quot;月亮&quot;">​</a></h1><p>暗蓝之月</p><p>A+4800<br> 替身外貌：<br> 暗蓝之月有着鱼人般的外表，全身覆盖着浅蓝色的湿滑皮肤，肌肉部分有暗蓝色的鱼鳞，扁平的头部生有两对眼睛和暗红色的斑纹，背上和双腿生有巨大而锋利的鱼鳍，关节部分长有可以自由开闭的鳃。<br> 替身数据：<br> 破坏力C 速度C（闪避防御） 射程C 持续力B 精密动作性C 成长性D<br> 替身对应主属性：敏捷<br> 替身能力：<br> 近距离力量型：近距离力量型都具有的基础能力，控制替身直接对目标进行肉搏攻击，检定方式为【决心—专注—主专业：替身使用—副专业：精神力（专注下属副专业）】。</p><p>水中强者：暗蓝之月是一种极端特化了水战能力的替身，仅在在海洋环境时替身的力量、速度、持续力都将提升到A级。</p><p>寄生藤壶：暗蓝之月在对目标造成伤害时会附带等量的【藤壶】异常点，强韧豁免，【藤壶】异常点一种基于疲乏升级而来的第四档异常点，表现为部分藤壶附着在目标被攻击部位依靠吸收目标体力而不断覆盖目标身体，具有与疲乏一样的不良效果，对疲乏点数生效的能力也对其起效。每轮结束时，具有该异常点的单位需要强韧豁免等于自身【藤壶】异常点数，增加失败值数点的【藤壶】异常点。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',7)])])}const f=r(d,[["render",i]]);export{b as __pageData,f as default};
